  "schema_name": "eywa_node_response",
  "schema_version": "v1",
  "orchestration_decision": "delegate",
  "decision_notes": "The problem requires verifying a step-by-step stack-based derivation of bracket matching. I will decompose this into state tracking, transition validation, and error localization.",
  "helpers": [
    {
      "label": "state_tracker",
      "instructions": "Extract the sequence of stack states provided in the derivation steps. For each step, record the contents of the stack and the current character being processed from the input sequence."
    },
    {
      "label": "transition_validator",
      "instructions": "For each step in the derivation, verify if the transition from the previous stack state to the current stack state follows the rules of a stack-based bracket matcher. A transition is valid if: 1. An opening bracket is encountered, it is pushed onto the stack. 2. A closing bracket is encountered, it matches the top element of the stack, and the top element is popped. 3. No other changes occur. Identify any step where the stack change does not match these rules."
    },
    {
      "label": "divergence_identifier",
      "instructions": "Compare the provided derivation steps against the expected logical behavior of a stack machine. Identify the specific step number where the stack content or the operation performed first deviates from the correct algorithm. If the derivation fails due to an empty stack when a closing bracket appears or a non-empty stack at the end, note that specific condition."
    }
  ],
  "synthesis_brief": "Combine the extracted states and the validation results to pinpoint the exact step number where the first logical error occurs. Use the divergence identifier to provide the final step number and the transition validator to provide the justification for why that step is incorrect."
}

